def get_knowledge_articles() -> List[Dict[str, Any]]:
    """获取所有知识库文章"""
    return KNOWLEDGE_ARTICLES


def get_articles_by_category(category: str) -> List[Dict[str, Any]]:
    """按分类获取文章"""
    return [a for a in KNOWLEDGE_ARTICLES if a.get("category") == category]


def get_articles_count() -> int:
    """获取文章总数"""
    return len(KNOWLEDGE_ARTICLES)
